#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 205;
struct Trie{int fail,son[30];}t[N];
struct Mat{int x,y;LD a[N][N];}Bas,Ans;
LL n,len,_26,Cnt=1,val[N];
LD uni,oput;
string ss[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void BuildTrie(string str){
    int now=1;
    for(char c:str){
        if(!t[now].son[c-'a'])
            t[now].son[c-'a']=(++Cnt);
        now=t[now].son[c-'a'];
    }val[now]=1;return;
}
void CountFail(){
    for(int i=0;i<_26;i++)t[0].son[i]=1;
    queue<int> q;
    while(!q.empty())q.pop();
    t[1].fail=0;q.push(1);
    while(!q.empty()){
        int u=q.front();q.pop();
        val[u]|=val[t[u].fail];
        for(int i=0;i<_26;i++){
            int fil=t[u].fail;
            while(!t[fil].son[i])fil=t[fil].fail;
            if(t[u].son[i])
                t[t[u].son[i]].fail=t[fil].son[i],
                q.push(t[u].son[i]);
            else t[u].son[i]=t[fil].son[i];
        }
    }return;
}
Mat operator * (const Mat &A,const Mat &B){
    Mat C;C.x=A.x,C.y=B.y;
    for(int i=1;i<=C.x;i++)
        for(int j=1;j<=C.y;j++)C.a[i][j]=0.0;
    for(int i=1;i<=C.x;i++)for(int j=1;j<=C.y;j++)
        for(int k=1;k<=A.y;k++)C.a[i][j]+=A.a[i][k]*B.a[k][j];
    return C;
}
void Init_bas(){
    Bas.x=Cnt+1,Bas.y=Cnt+1;
    for(int i=1;i<=Bas.x;i++)
        for(int j=1;j<=Bas.y;j++)Bas.a[i][j]=0.0;
    for(int u=1;u<=Cnt;u++)
        for(int i=0;i<_26;i++){
            int v=t[u].son[i];
            if(val[v])Bas.a[u][1]+=uni,Bas.a[u][Cnt+1]+=uni;
            else Bas.a[u][v]+=uni;
        }
    Bas.a[Bas.x][Bas.y]=1.0;return;
}
Mat Mqp(LL k){
    Init_bas();
    Ans.x=Bas.x,Ans.y=Bas.y;
    for(int i=1;i<=Ans.x;i++)
        for(int j=1;j<=Ans.y;j++)Ans.a[i][j]=(LD)(i==j);
    while(k){if(k&1)Ans=Ans*Bas;Bas=Bas*Bas,k>>=1;}
    return Ans;
}
int main(){
    n=read(),len=read(),_26=read();
    uni=(LD)(1.0/_26);
    for(int i=1;i<=n;i++)
        {cin>>ss[i];BuildTrie(ss[i]);}
    CountFail();
    oput=Mqp(len).a[1][Cnt+1];
    printf("%.8Lf\n",oput);
    return 0;
}
